#include "tsl2591.h"
#include <Wire.h>
#include <Adafruit_TSL2591.h>
static Adafruit_TSL2591 tsl(2591);
static float _lux=0;static uint16_t _ir=0,_full=0;static unsigned long _l=0;
void tsl2591_setup(){Wire.begin();if(!tsl.begin()){Serial.println("[tsl2591] Fail!");return;}tsl.setGain(TSL2591_GAIN_MED);tsl.setTiming(TSL2591_INTEGRATIONTIME_300MS);Serial.println("[tsl2591] OK");}
void tsl2591_loop(){if(millis()-_l<500)return;_l=millis();uint32_t lum=tsl.getFullLuminosity();_ir=lum>>16;_full=lum&0xFFFF;_lux=tsl.calculateLux(_full,_ir);}
float tsl2591_get_lux(){return _lux;}
uint16_t tsl2591_get_ir(){return _ir;}
uint16_t tsl2591_get_full(){return _full;}
